import json, os
ROBOT_PATH = {{primary_robot.path}}
BASE_MODEL_ID = {{groot_policy.model_id}}
EMBODIMENT = {{groot_policy.embodiment}}
EVAL_TASK = {{eval_task.task_id}}
NUM_EPISODES = {{eval_task.num_episodes}}
RESULT_FILE = {{eval_task.result_file}}
os.makedirs('/tmp', exist_ok=True)
vram_check = check_vram_headroom(operation='groot_inference', num_envs=1, complexity='medium')
if isinstance(vram_check, dict) and not vram_check.get('headroom_ok', True):
    raise RuntimeError(f"Insufficient VRAM: {vram_check.get('message', '')}")
load_result = load_groot_policy(robot_path=ROBOT_PATH, model_id=BASE_MODEL_ID, embodiment=EMBODIMENT)
server_url = load_result.get('server_url', 'localhost:8080') if isinstance(load_result, dict) else 'localhost:8080'
sim_control(action='play')
eval_result = evaluate_groot(task=EVAL_TASK, model_id=BASE_MODEL_ID, num_episodes=NUM_EPISODES)
success_rate = eval_result.get('success_rate', None) if isinstance(eval_result, dict) else None
result_payload = {'task_id': 'CP-NEW-groot-load-eval-live', 'model_id': BASE_MODEL_ID, 'eval_task': EVAL_TASK, 'num_episodes': NUM_EPISODES, 'success_rate': success_rate, 'server_url': server_url, 'pipeline_ok': success_rate is not None}
with open(RESULT_FILE, 'w') as f:
    json.dump(result_payload, f, indent=2)
assert result_payload['pipeline_ok'], f'Pipeline connectivity FAILED: evaluate_groot did not return success_rate. Server: {server_url}'
